member.example:
Bind the Graphic color property using a serialized binder field — the target Graphic is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private GraphicColorBinder _color;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public Color _color;
    }


Bind the Graphic color property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private Graphic _graphic;
        
        private GraphicColorBinder Color =>
            new(_graphic);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public Color _color;
    }

Switch the Graphic color between two values using a serialized binder field — the target Graphic is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private GraphicColorSwitcherBinder _isHighlighted;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isHighlighted;
    }


Switch the Graphic color between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private Graphic _graphic;
        
        private GraphicColorSwitcherBinder IsHighlighted => new(
            _graphic, Color.yellow, Color.white);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isHighlighted;
    }
